features.snippet:
(* whitebox *)
module mymodule (
    input clk,
    input rst,
    output reg [7:0] data
);
always @(posedge clk) data <= data + 1;
endmodule

(* lib_whitebox *)
module lib_cell (
    input a,
    input b,
    output y
);
assign y = a & b;
endmodule

(* blackbox *)
module empty_mod (
    input [7:0] in,
    output [7:0] out
);
endmodule

(* whitebox, lib_whitebox = 0 *)
module attr_mod (
    input clk,
    output reg q
);
always @(posedge clk) q <= 0;
endmodule
